INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1851', 'Torrevieja: superbes appartements 3 chambres dans un environnement privilégié', '', '', 'Cette nouvelle résidence dispose d''une situation unique entre le parc naturel des Lagunas de la Mata et la Laguna Rosa de Torrevieja. Vous pourrez en seulement quelques minutes rejoindre les belles plages de Torrevieja (La Mata, Los Locos,...), le port, les boutiques et commerces, et les nombreux restaurants que compte Torrevieja. La résidence jouira de grands espaces communs avec 2 piscines pour adultes, 2 bassins pour enfants, 2 jacuzzis, une aire de jeux pour enfants, des terrains de pétanque et des espaces verts aménagés avec de nombreuses plantes, palmiers, fontaines, sentiers... La 1ère phase comptera 240 logements (appartements 1, 2, 3 chambres et villas). Les appartements du rez-de-chaussée disposeront d''un jardin et ceux du dernier étage d''un solarium, les étages intermédiaires auront une belle grande terrasse. Les appartements 3 chambres sont équipés de deux salles de bains, d''une cuisine ouverte sur un spacieux salon/salle à manger avec baies vitrées vers la terrasse et d''une buanderie. Place de parking. Prix: à partir de 345.000 ? hors frais Livraison: Novembre 2025 -Mai 2026', '', '', 345000, 'torrevieja-superbes-appartements-3-chambres-dans-un-environnement-privilegie', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1854', 'Condado de Alhama: belles villas 3 chambres dans un luxueux golf', '', '', 'Ces belles villas modernes sont situées à Condado de Alhama, dans un complexe de luxe, avec des zones sportives et entourées par la nature, tous les services et plusieurs terrains de golf. Les plages de Mazarrón se trouvent à 25 minutes en voiture et la belle ville de Murcie à 30 minutes. Les villas 3 chambres sont situées sur des parcelles allant de 345 m² à 364 m² et disposent de 2 salles de bains, d''une cuisine ouverte sur un séjour lumineux avec baies vitrées vers la terrasse et le jardin. Piscine de 21 m². Solarium de 75 m², place de parking. Inclus dans le prix: - Éclairage LED dans la cuisine et les salles de bains - Volets électriques - Point de recharge pour voiture électrique Prix: à partir de 335.000 ? hors frais', '', '', 335000, 'condado-de-alhama-belles-villas-3-chambres-dans-un-luxueux-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1856', 'Casares: superbes appartements 2 chambres', '', '', 'Cette nouvelle résidence est située à Casares, une zone entre mer et montagnes, offrant un large éventail de loisirs et de divertissements, dont de nombreux terrains de golf prestigieux (Finca Cortesin, Casares Golf) ainsi que de superbes plages de sable fin. Du charme historique de Casares Pueblo à la promenade animée d''Estepona, il y en aura pour tous les goûts! La résidence comptera 134 appartements 2, 3 ou 4 chambres, situés dans une oasis de nature, en face d''un parcours de golf et offrant de belles vues dégagées sur la mer ou la montagne. Ce complexe est fermé et contrôlé par des agents de sécurité et offre une salle de sport intérieure, une piscine commune et de vastes espaces de jardin. Les appartements 2 disposent de 2 salles de bains, d''un beau séjour lumineux donnant sur une grande terrasse et d''une cuisine équipée ouverte. Chaque appartement a une place de parking en souterrain et une cave. Prix: à partir de 323.000 ? hors frais Fin des travaux: 3T2026', '', '', 323000, 'casares-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1857', 'Casares: superbes appartements 3 chambres', '', '', 'Cette nouvelle résidence est située à Casares, une zone entre mer et montagnes, offrant un large éventail de loisirs et de divertissements, dont de nombreux terrains de golf prestigieux (Finca Cortesin, Casares Golf) ainsi que de superbes plages de sable fin. Du charme historique de Casares Pueblo à la promenade animée d''Estepona, il y en aura pour tous les goûts! La résidence comptera 134 appartements 2, 3 ou 4 chambres, situés dans une oasis de nature, en face d''un parcours de golf et offrant de belles vues dégagées sur la mer ou la montagne. Ce complexe est fermé et contrôlé par des agents de sécurité et offre une salle de sport intérieure, une piscine commune et de vastes espaces de jardin. Les appartements 3 disposent de 2 salles de bains, d''un beau séjour lumineux donnant sur une grande terrasse et d''une cuisine équipée ouverte. Chaque appartement a une place de parking en souterrain et une cave. Prix: à partir de 362.000 ? hors frais Fin des travaux: 3T2026', '', '', 362000, 'casares-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1858', 'Estepona: beaux appartements 2 chambres', '', '', 'Cette résidence est située dans le quartier d''Estepona Golf, dans un environnement très attrayant pour ceux qui veulent profiter d''une vie tranquille et pour les amateurs de golf. Le complexe résidentiel est situé sur une colline avec une vue dégagée et entouré d''espaces verts, dans un cadre naturel idéal pour le repos et la détente, mais à proximité de tous les services dont vous pourriez avoir besoin, comme les supermarchés, centres scolaires, restaurants, loisirs ou même un hôpital à quelques minutes en voiture. Ce projet se trouve à quelques minutes du littoral, entre la marina d''Estepona et ses installations de loisirs attrayantes et la baie de Casares. La résidence compte 2 piscines communes, un terrain multi-sports, un club social et de vastes espaces verts. Il y aura au total 90 appartements 1, 2 ou 3 chambres répartis dans un complexe fermé et sécurisé. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine équipée ouverte sur le vaste séjour, d''une belle terrasse, d''une place de parking en souterrain ainsi que d''un débarras. Les appartements du rez-de-chaussée disposent en outre d''un jardin. Certains appartements sont en duplex, avec solarium. Prix: à partir de 301.000 ? hors frais KEY READY', '', '', 301000, 'estepona-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1860', 'Casares: magnifiques appartements 2 chambres proches de mer', '', '', 'Cette nouvelle résidence est située à Casares, à 500 m de la mer. La région de Casares offre de nombreuses activités de loisirs, dont de nombreux terrains de golf prestigieux (Finca Cortesin, Casares Golf) ainsi que de superbes plages de sable fin. Le village typique de Casares Pueblo ainsi que la promenade animée d''Estepona se trouvent à proximité. Les appartements 2 chambres et 2 salles de bains disposent d''une cuisine équipée ouverte et d''un lumineux séjour avec baies vitrées vers la terrasse. Chaque appartement a également une place de parking et une cave. Les appartements du rez ont un beau jardin privatif, les appartements du 1er étage jouissent d''une belle terrasse. La résidence comprendra de vastes espaces aménagés en jardins, deux piscines extérieures, une salle de coworking, une salle de détente avec piscine, une salle de gym, un espace zen, un espace lecture, une aire de jeux pour enfants... Le complexe, fermé et sécurisé, disposera également de différents chemins piétons intérieurs, adaptés aux personnes à mobilité réduite. La résidence propose également des appartements 3 et 4 chambres Prix: à partir de 398.000 ? hors frais Inclus dans le prix: - taque vitrocéramique, four, micro-ondes, hotte, frigo, lave-vaisselle et lave-linge - climatisation - chauffage au sol dans la salle de bains principale Fin des travaux: entre décembre 2026 et mars 2027', '', '', 398000, 'casares-magnifiques-appartements-2-chambres-proches-de-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1861', 'DERNIERE UNITE ! Casares: magnifique penthouse 3 chambres proches de mer', '', '', 'Cette nouvelle résidence est située à Casares, à 500 m de la mer. La région de Casares offre de nombreuses activités de loisirs, dont de nombreux terrains de golf prestigieux (Finca Cortesin, Casares Golf) ainsi que de superbes plages de sable fin. Le village typique de Casares Pueblo ainsi que la promenade animée d''Estepona se trouvent à proximité. Les appartements 3 chambres et 2 salles de bains disposent d''une cuisine équipée ouverte et d''un lumineux séjour avec baies vitrées vers la terrasse. Chaque appartement a également une place de parking et une cave. Situés aux 2èmes et 3èmes étages, ils disposent de belles terrasses. Au 4ème étage, les penthouses avec solarium jouissent de magnifiques vues sur mer. La résidence comprendra de vastes espaces aménagés en jardins, deux piscines extérieures, une salle de coworking, une salle de détente avec piscine, une salle de gym, un espace zen, un espace lecture, une aire de jeux pour enfants... Le complexe, fermé et sécurisé, disposera également de différents chemins piétons intérieurs, adaptés aux personnes à mobilité réduite. La résidence propose également des appartements 2 et 4 chambres Prix: Penthouse: 660.000 ? hors frais Inclus dans le prix: - taque vitrocéramique, four, micro-ondes, hotte, frigo, lave-vaisselle et lave-linge - climatisation - chauffage au sol dans la salle de bains principale Fin des travaux: entre décembre 2026 et mars 2027', '', '', 660000, 'derniere-unite-casares-magnifique-penthouse-3-chambres-proches-de-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1862', 'Casares: beaux appartements 2 chambres', '', '', 'Cette nouvelle résidence est située dans la municipalité de Casares, à proximité du parc naturel de la Sierra Bermeja et de villages pittoresques tels que Manilva, Estepona et, à l''intérieur des terres, Gaucín et Genalguacil. Casares est l''un des plus charmants villages blancs d''Andalousie, situé entre la mer et ses superbes plages de sable fin et la montagne. De nombreux parcours de golf se trouvent également à proximité. La résidence compte une piscine commune, des jardins et une aire de jeux pour enfants. La topographie du lieu permet des vues à 360º sur la mer et les montagnes. Le complexe se compose de 47 appartements 1, 2 et 3 chambres. Tous les logements disposent d''une cuisine équipée, de grandes terrasses et d''équipements de qualité tels que l''eau chaude par aérothermie et la pré-installation pour la recharge des véhicules électriques. Les appartements au rez-de-chaussée ont un jardin privé et chaque appartement dispose d''un garage et d''un local de rangement. Prix: à partir de 333.000 ? hors frais Fin des travaux : 2T2025', '', '', 333000, 'casares-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1863', 'DERNIERE UNITE ! Casares: beaux appartements 3 chambres', '', '', 'Cette nouvelle résidence est située dans la municipalité de Casares, à proximité du parc naturel de la Sierra Bermeja et de villages pittoresques tels que Manilva, Estepona et, à l''intérieur des terres, Gaucín et Genalguacil. Casares est l''un des plus charmants villages blancs d''Andalousie, situé entre la mer et ses superbes plages de sable fin et la montagne. De nombreux parcours de golf se trouvent également à proximité. La résidence compte une piscine commune, des jardins et une aire de jeux pour enfants. La topographie du lieu permet des vues à 360º sur la mer et les montagnes. Le complexe se compose de 47 appartements 1, 2 et 3 chambres. Tous les logements disposent d''une cuisine équipée, de grandes terrasses et d''équipements de qualité tels que l''eau chaude par aérothermie et la pré-installation pour la recharge des véhicules électriques. Les appartements au rez-de-chaussée ont un jardin privé et chaque appartement dispose d''un garage et d''un local de rangement. Prix: 360.000 ? hors frais Fin des travaux : 2T2025', '', '', 360000, 'derniere-unite-casares-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1865', 'San Miguel de Salinas: superbes villas de plain-pied en 3 chambres', '', '', 'Ces superbes villas 3 chambres sont situées à San Miguel de Salinas, à une dizaine de minutes en voiture des plages de Torrevieja ou de Campoamor. Le village typique de San Miguel a l''avantage de proposer tous les types de produits et de services. Les restaurants et les bars ne manquent pas non plus. Les golfs de las Colinas, de Vistabella, de Villamartin et de Campoamor sont à quelques minutes des villas. Les villas de plain-pied, situées sur des terrains allant de 316 m² à 346 m², disposent de 3 chambres, de 2 salles de bains, d''une cuisine ouverte sur un lumineux et spacieux séjour avec accès à la terrasse et au jardin avec piscine privée (en option). Toutes les chambres ont également un accès direct à la terrasse. Vaste solarium de 86 m². Place de parking. Prix: à partir de 404.900 ? hors frais Piscine privée en option Fin des travaux: 30/04 ou 30/09/2026', '', '', 404900, 'san-miguel-de-salinas-superbes-villas-de-plain-pied-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1869', 'Bonalba Golf: superbes appartements 3 chambres', '', '', 'Ce nouveau complexe résidentiel se situe sur le terrain de golf de Bonalba, situation privilégiée à quelques minutes de Mutxamel, d''El Campello, de la ville d''Alicante, des plages, des supermarchés, des centres commerciaux, des restaurants, de l''université, de l''hôpital et de l''aéroport international. La résidence offre une vue imprenable sur la mer. Le complexe propose des appartements 2 et 3 chambres avec de belles grandes terrasses, ainsi que des villas individuelles 2, 3 ou 4 chambres. Superbe piscine commune. Les appartements 3 chambres disposent de 2 salles de bains et d''une cuisine ouverte donnant sur le living avec baies vitrées vers la terrasse. Place de parking en souterrain et cave. Prix: à partir de 310.500 ? hors frais', '', '', 310500, 'bonalba-golf-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1870', 'Bonalba Golf: belles villas 2 chambres avec vue sur mer', '', '', 'Ce nouveau complexe résidentiel se situe sur le terrain de golf de Bonalba, situation privilégiée à quelques minutes de Mutxamel, d''El Campello, de la ville d''Alicante, des plages, des supermarchés, des centres commerciaux, des restaurants, de l''université, de l''hôpital et de l''aéroport international. La résidence offre une vue imprenable sur la mer. Le complexe propose des appartements 2 et 3 chambres avec de belles grandes terrasses, ainsi que des villas individuelles 2, 3 ou 4 chambres. Superbe piscine commune. Les villas 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur le salon avec baies vitrées vers la terrasse et le jardin. Place de parking. Prix: à partir de 310.000 ? hors frais', '', '', 310000, 'bonalba-golf-belles-villas-2-chambres-avec-vue-sur-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1871', 'Torrevieja - Los Balcones: superbes appartements 2 chambres avec vue sur les salines', '', '', 'Cette nouvelle résidence est idéalement située à ''Los Balcones'', un quartier de Torrevieja, à 5 minutes en voiture des belles plages de Orihuela Costa et de nombreux terrains de golf. A distance de marche, vous trouverez un supermarché, des petits commerces, cafés et restaurants ainsi qu''un hôtel avec Spa. La résidence offre de jolies vues sur les salines de Torrevieja (le fameux lac rose) et comptera 48 unités. Les appartements 2 chambres disposent de 2 salles de bains et d''une cuisine ouverte sur un lumineux séjour. Les appartements du rez disposent de deux terrasses (l''une à l''avant et l''autre à l''arrière), ceux du 1er étage ont 2 balcons ainsi qu''un beau solarium. Les parties communes comprennent un grand jardin, une piscine à débordement à deux niveaux avec vue sur le lagon et une cascade, ainsi qu''un espace pour les enfants. Possibilité de place de parking et de cave en sous-sol moyennant supplément. Prix: Rez: à partir de 299.900 ? hors frais 1er étage: à partir de 329.900 ? hors frais Fin des travaux: mars ou décembre 2026', '', '', 299900, 'torrevieja-los-balcones-superbes-appartements-2-chambres-avec-vue-sur-les-salines', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1872', 'Condado de Alhama: beaux appartements 2 chambres', '', '', 'Cette belle résidence est située sur le golf de Alhama (Murice), dans un complexe de luxe, avec des zones sportives et entourée par la nature et tous les services. Les appartements 2 chambres disposent de 2 salles de bains, d''un living avec accès à une belle terrasse avec vue sur la nature environnante. Les appartements du rez-de-chaussée ont également un jardin, et ceux du troisième étage jouissent d''un solarium. Chaque appartement a sa propre place de parking. Piscine commune. Prix: à partir de 191.900 ? hors frais', '', '', 191900, 'condado-de-alhama-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1875', 'El Verger: superbes appartements 3 chambres à 500 m de la mer', '', '', 'A El Verger, non loin de Denia, cette nouvelle résidence est située à 500 m de la mer et à proximité de nombreuses facilités, telles que supermarchés, bars, restaurants... La résidence compte plusieurs zones communes pour vous balader ou pratiquer du sport, ainsi qu''une superbe piscine, un club social, un terrain de pétanque, un espace détente, un point de recharge pour vélos électriques... Les résidents auront également accès à un club social privé à la plage avec parking, piscine, douches, casiers,... Le projet est conçu autour des stratégies durables : des systèmes de collecte, de canalisation et de réutilisation des eaux de pluie; des jardins rafraîchissants avec des espèces indigènes nécessitant un entretien minimal; des panneaux photovoltaïques pour la production d''énergie par autoconsommation; plusieurs bornes de recharge pour véhicules électriques. Les appartements chambres et 2 ou 3 salles de bains sont spacieux et disposent de belles grandes terrasses vous permettant de profiter pleinement du climat méditerranéen. Prix: à partir de 354.000 ? hors frais Penthouses: à partir de 475.000 ? hors frais Inclus dans le prix: - climatisation - électroménagers: taque à induction, four, micro-ondes et hotte', '', '', 354000, 'el-verger-superbes-appartements-3-chambres-a-500-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1886', 'Finestrat: superbes appartements 2 chambres avec vue sur la baie de Benidorm', '', '', 'Découvrez ce développement résidentiel exclusif, à Finestrat - Benidorm. La résidence propose 78 appartements répartis en 5 bâtiments, dans un environnement privilégié. Chaque appartement dispose de 2 chambres et 2 salles de bains, d''une grande terrasse et de belles vues sur Bénidorm et la mer Méditerranée. La résidence propose 3 piscines communes, un terrain de paddle et d''un espace de jeux pour enfants. Profitez de tout ce que Bénidorm a à offrir tout en bénéficiant du calme de Finestrat! Prix: à partir de 289.900 ? hors frais (avec place de parking) Fin des travaux: mars 2026 ou décembre 2026', '', '', 289900, 'finestrat-superbes-appartements-2-chambres-avec-vue-sur-la-baie-de-benidorm', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1887', 'Denia: beaux appartements 2 chambres', '', '', 'A Denia, ce nouveau complexe résidentiel comptera 29 magnifiques appartements 2 ou 3 chambres avec piscine commune. Il est situé dans un emplacement imbattable, à 2 km du centre ville et à 100 mètres de la plage. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur le living, d''une buanderie et d''une place de parking. En fonction de leur situation (rez, 1er étage ou 2ème étage) ils auront une terrasse, un jardin ou un solarium. Prix: à partir de 315.000 ? hors frais Fin des travaux: fin juillet 2025', '', '', 315000, 'denia-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1888', 'Denia: beaux appartements 3 chambres', '', '', 'A Denia, ce nouveau complexe résidentiel comptera 29 magnifiques appartements 2 ou 3 chambres avec piscine commune. Il est situé dans un emplacement imbattable, à 2 km du centre ville et à 100 mètres de la plage. Les appartements 3 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur le living, d''une buanderie et d''une place de parking. En fonction de leur situation (rez, 1er étage ou 2ème étage) ils auront une terrasse, un jardin ou un solarium. Prix: à partir de 325.000 ? hors frais Fin des travaux: fin juillet 2025', '', '', 325000, 'denia-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1889', 'Llíber: superbes villas exclusives en 3 chambres', '', '', 'Ces superbes villas sont situées dans la municipalité de Llíber. Il s''agit d''une Eco Résidence, basée sur le respect de l''environnement, la transmission des valeurs de la culture locale et le bien-être de ses résidents en promouvant la vie communautaire et un mode de vie sain en contact avec la nature. L''architecture des villas est basée sur les couleurs de la terre, sur les murs en pierre sèche, sur la végétation indigène de la région, ce qui permet aux maisons de se fondre dans le paysage de la Vallée del Pop. Leur conception et leur équipement favorisent une faible consommation d''énergie. Les maisons disposent d''un système aérothermique pour le chauffage et la production d''eau chaude sanitaire, d''un chauffage par le sol, de l''installation de panneaux photovoltaïques, d''un système de ventilation motorisé, d''une borne de recharge pour voiture électrique, de la domotique, de jardins en terrasses avec des murs en pierre traditionnels et des plantes indigènes, entre autres. De plus, afin de garantir une mobilité respectueuse dans le complexe résidentiel, une voiture ou deux vélos électriques sont inclus dans chaque maison. Les 14 villas sont construites sur des parcelles de 400 à 700 mètres carrés, et sont réparties sur deux étages. Elles disposent de 3 chambres et de 2 salles de bains, d''une piscine privée, d''un parking, d''une salle de stockage et d''impressionnantes vues ouvertes sur les vignobles et le magnifique environnement naturel de la Vallée del Pop. Vous pourrez choisir entre 2 modèles différents. Prix: de 930.000 ? à 990.000 ? hors frais', '', '', 930000, 'lliber-superbes-villas-exclusives-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1890', 'Manilva: penthouses 2 chambres avec vue sur mer', '', '', 'Belle résidence idéalement située à Manilva, à quelques minutes à pied de la plage et à proximités de plusieurs parcours de golf et de toutes les commodités. La résidence comptera 100 appartements spacieux 2 ou 3 chambres, tous bénéficiant de superbes vues sur la Méditerranée. Les appartements 2 chambres disposent de 2 salles de bains. La cuisine, entièrement meublée et équipée avec tous les électroménagers, est ouverte sur le salon-living avec accès à la belle terrasse. La chambre parentale dispose également d''un accès direct à la terrasse. Tous les appartements disposent d''une cave et d''une place de parking en sous-sol. Les belles zones communes comprennent de grands jardins, deux piscines avec chloration saline, un espace de relaxation et de yoga, un spa avec bain turc, jacuzzi et sauna, un espace de fitness intérieur, une salle de loisirs avec espace de coworking, multimédia et jeux,... Ce projet est parfait si vous êtes à la recherche d''un appartement avec vue sur mer. Prix: penthouses à partir de 530.000 ? Inclus dans le prix: - électroménagers - climatisation - cave et place de parking Fin des travaux : 1T2027', '', '', 530000, 'manilva-penthouses-2-chambres-avec-vue-sur-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1891', 'Manilva: superbes appartements 3 chambres avec vue sur mer', '', '', 'Belle résidence idéalement située à Manilva, à quelques minutes à pied de la plage et à proximités de plusieurs parcours de golf et de toutes les commodités. La résidence comptera 100 appartements spacieux 2 ou 3 chambres, tous bénéficiant de superbes vues sur la Méditerranée. Les appartements 3 chambres disposent de 2 salles de bains. La cuisine, entièrement meublée et équipée avec tous les électroménagers, est ouverte sur le salon-living avec accès à la belle terrasse. La chambre parentale dispose également d''un accès direct à la terrasse. Tous les appartements disposent d''une cave et d''une place de parking en sous-sol. Les belles zones communes comprennent de grands jardins, deux piscines avec chloration saline, un espace de relaxation et de yoga, un spa avec bain turc, jacuzzi et sauna, un espace de fitness intérieur, une salle de loisirs avec espace de coworking, multimédia et jeux,... Ce projet est parfait si vous êtes à la recherche d''un appartement avec vue sur mer. Prix: à partir de 364.000 ? hors frais Inclus dans le prix: - électroménagers - climatisation - cave et place de parking Fin des travaux : 1T2027', '', '', 364000, 'manilva-superbes-appartements-3-chambres-avec-vue-sur-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1892', 'Estepona: superbes appartements 2 chambres', '', '', 'Nouvelle promotion située dans la région d''Estepona, dans un quartier tranquille, à quelques minutes de la plage. Le projet se compose de 41 appartements 1, 2 ou 3 chambres, répartis dans deux bâtiments, avec des propriétés au rez-de-chaussée, au premier et au deuxième étage. Toutes les propriétés sont orientées au sud-est. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur un spacieux séjour avec baies vitrées vers la terrasse. L''ensemble offre de beaux jardins paysagers, une piscine commune, une salle de sport et une salle polyvalente. Prix: à partir de 448.000 ? hors frais Inclus dans le prix: - électroménagers - climatisation - place de parking en sous-sol et remise Fin des travaux: 3T2026', '', '', 448000, 'estepona-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1893', 'Estepona: superbes appartements 3 chambres', '', '', 'Nouvelle promotion située dans la région d''Estepona, dans un quartier tranquille, à quelques minutes de la plage. Le projet se compose de 41 appartements 1, 2 ou 3 chambres, répartis dans deux bâtiments, avec des propriétés au rez-de-chaussée, au premier et au deuxième étage. Toutes les propriétés sont orientées au sud-est. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur un spacieux séjour avec baies vitrées vers la terrasse. L''ensemble offre de beaux jardins paysagers, une piscine commune, une salle de sport et une salle polyvalente. Prix: à partir de 390.000 ? hors frais Inclus dans le prix: - électroménagers - climatisation - place de parking en sous-sol et remise Fin des travaux: 3T2026', '', '', 390000, 'estepona-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1894', 'Candelada: très beaux appartements 2 chambres', '', '', 'Nouveau complexe résidentiel comprenant 56 appartements 2 et 3 chambres, situé dans le cadre privilégié du Golden Mile d''Estepona. Les appartements disposent de grandes terrasses orientées sud-ouest. Ce projet combine des finitions de qualité avec des espaces intérieurs et extérieurs spacieux. Son architecture avant-gardiste se combine avec ses espaces communs équipés d''une piscine extérieure, d''un espace de coworking, d''un espace fitness et de deux terrains de pétanque. En outre, les propriétaires auront accès au Santa Vista Club, qui offre une large gamme d''installations et de services de loisirs. L''emplacement du projet est imbattable, à quelques pas du charmant village de Cancelada et à proximité de plusieurs terrains de golf. Prix: à partir de 342.000 ? Inclus: - électroménagers - climatisation - place de parking en sous-sol Fin des travaux: 4T2024', '', '', 342000, 'candelada-tres-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1895', 'Candelada: très beaux appartements 3 chambres', '', '', 'Nouveau complexe résidentiel comprenant 56 appartements 2 et 3 chambres, situé dans le cadre privilégié du Golden Mile d''Estepona. Les appartements disposent de grandes terrasses orientées sud-ouest. Ce projet combine des finitions de qualité avec des espaces intérieurs et extérieurs spacieux. Son architecture avant-gardiste se combine avec ses espaces communs équipés d''une piscine extérieure, d''un espace de coworking, d''un espace fitness et de deux terrains de pétanque. En outre, les propriétaires auront accès au Santa Vista Club, qui offre une large gamme d''installations et de services de loisirs. L''emplacement du projet est imbattable, à quelques pas du charmant village de Cancelada et à proximité de plusieurs terrains de golf. Prix: à partir de 385.500 ? Inclus: - électroménagers - climatisation - place de parking en sous-sol Fin des travaux: 4T2024', '', '', 385500, 'candelada-tres-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
